@dataclass
class KickoffChecklistItem:
    kr_id: str
    cascade_aligned: bool
    data_source_live: bool
    baseline_value: Optional[float]
    owner_acknowledged: bool
    blocking_dependency_resolved: bool

    def is_ready(self) -> bool:
        return (
            self.cascade_aligned
            and self.data_source_live
            and self.baseline_value is not None
            and self.owner_acknowledged
            and self.blocking_dependency_resolved
        )

    def blockers(self) -> list[str]:
        issues = []
        if not self.cascade_aligned:         issues.append("not mapped to programme OKR")
        if not self.data_source_live:        issues.append("data source not configured")
        if self.baseline_value is None:      issues.append("baseline value not set")
        if not self.owner_acknowledged:      issues.append("owner not confirmed")
        if not self.blocking_dependency_resolved: issues.append("upstream dependency blocked")
        return issues

@dataclass
class PulseUpdate:
    kr_id: str
    owner: str
    week: int
    current_value: float
    rag: RAGStatus
    one_line_note: str   # max 140 characters: what changed, why we're on/off track

def aggregate_pulse(updates: list[PulseUpdate]) -> dict:
    counts = {s: 0 for s in RAGStatus}
    for u in updates:
        counts[u.rag] += 1
    attention_needed = [u for u in updates if u.rag in (RAGStatus.AMBER, RAGStatus.RED)]
    return {
        "rag_counts": {s.value: counts[s] for s in RAGStatus},
        "attention_needed": [(u.kr_id, u.rag.value, u.one_line_note) for u in attention_needed],
        "auto_escalate_to_programme_lead": len([u for u in updates if u.rag == RAGStatus.RED]) > 0,
    }
